import React from 'react'
import Header from '../component/Header'
import Footer from '../component/Footer'

export default function Abount() {
    return (
        <div>
            <Header active='/about' />
            <Footer />
            <h1 className='text-2xl mt-60 text-red-500 w-4xl ml-70'>Prezidentimiz SH.M. Mirziyoyevning 2021 - yil 21-22 yanvar kunlari Buxoro viloyatiga tashrifi davomida va Xalq deputatlari viloyat Kengashining navbatdagi tashqari sessiyasida bergan topshiriqlari bo'yicha 4 - sonli bayonining 98 - bandiga asosan tashkil etilgan.

                Oliygoximizda bugungi kunda 3 ta kampus umumiy hisobda 6000 o`rinli o`quv binosi hamda 420 o`rinli talabalar yotoqxonasi mavjud. Bizda jami 16 ta bakalavr, 8 ta magistratura hamda 6 ta ta`lim shakli bo`yicha DOKTORANTURA (Psixologiya, Filologiya, Pedagogika fanlari bo'yicha) mavjud.</h1>
        </div>
    )
}
